result: { name: string; imageUrl: string } | null = null;

play(): void {
  if (!this.userName.trim()) return;

  const hash = this.simpleHash(this.userName.trim());
  const index = hash % this.characters.length;
  this.result = this.characters[index];
}

// Petit hash simple : transforme une string en nombre
simpleHash(str: string): number {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = (hash * 31 + str.charCodeAt(i)) >>> 0; // >>>0 pour forcer entier positif
  }
  return hash;
}
